export type TeamMember = (typeof TEAM)[number]

const INTERNAL_IDS = new Set(['ayaz', 'hrithik', 'sarah', 'aya'])

export function isInternalStaff(nameOrId: string): boolean {
  const n = nameOrId.toLowerCase().trim()
  return (
    INTERNAL_IDS.has(n) ||
    n.includes('ayaz') ||
    n.includes('hrithik') ||
    n.includes('sarah shaheen') ||
    (TEAM as unknown as TeamMember[]).some(
      (member) => !member.isClientFacing && member.name.toLowerCase().includes(n),
    )
  )
}

export function getClientFacingTeam(): TeamMember[] {
  return (TEAM as unknown as TeamMember[]).filter((member) => member.isClientFacing)
}

export function hasUsableContact(member: TeamMember): boolean {
  if (!member.isClientFacing) return false
  if (!member.phone || !member.wa) return false
  if (/[xX]{2,}/.test(member.phone) || /[xX]{2,}/.test(member.wa)) return false
  return true
}

export function findAgentByName(hint: string): TeamMember | undefined {
  const normalizedHint = hint.toLowerCase()
  return (TEAM as unknown as TeamMember[]).find(
    (member) => member.isClientFacing === true && member.name.toLowerCase().includes(normalizedHint),
  )
}

export function findBestAgent(area?: string, budget?: number): TeamMember {
  const team = getClientFacingTeam()
  const reachable = team.filter(hasUsableContact)
  const pool = reachable.length > 0 ? reachable : team

  if (budget && budget >= 5_000_000) {
    return pool.find((member) => member.id === 'imran') ?? pool.find((member) => member.isDefault) ?? pool[0]
  }

  if (area) {
    const normalizedArea = area.toLowerCase()
    const match = pool.find(
      (member) =>
        Array.isArray(member.areas) &&
        member.areas.length > 0 &&
        member.areas.some(
          (zone) => zone.toLowerCase().includes(normalizedArea) || normalizedArea.includes(zone.toLowerCase()),
        ),
    )
    if (match) return match
  }

  return pool.find((member) => member.isDefault && hasUsableContact(member)) ?? pool[0]
}

export function agentCard(agent: TeamMember, lang: 'en' | 'ar'): string {
  if (!hasUsableContact(agent)) {
    const ceo = (TEAM as unknown as TeamMember[]).find((member) => member.id === 'imran')
    if (ceo && hasUsableContact(ceo)) return agentCard(ceo, lang)
    return ''
  }

  const wa = `https://wa.me/${agent.wa}`
  if (lang === 'ar') {
    return `━━━━━━━━━━━━━━━━━━\n👤 *${agent.name}*\n🏷 ${agent.role}\n📞 ${agent.phone}\n💬 واتساب: ${wa}\n━━━━━━━━━━━━━━━━━━`
  }
  return `━━━━━━━━━━━━━━━━━━\n👤 *${agent.name}*\n🏷 ${agent.role}\n📞 ${agent.phone}\n💬 WhatsApp: ${wa}\n━━━━━━━━━━━━━━━━━━`
}
